"""
MKT Context Commentary — Jude ch1
24 missing verses (v4 already present)
Run: python3 scripts/zc-context-jude-1-1.py

Key historical-cultural sources:
- 1 Enoch: Watchers tradition (ch6-16), Enoch's prophecy (1:9), wandering stars
- Assumption of Moses (aka Testament of Moses): Michael/devil dispute over Moses's body (v9)
- Num 14, 16; Gen 4, 6, 19: OT types underlying vv5-11
- Psychikos/pneumatikos distinction: 1 Cor 2:14-15 background for v19
- Agape meal in early Christianity: v12
- Greco-Roman agonistic culture: epagonizesthai (v3)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CONTEXT = {
  "1": {
    "1": '<p>Jude identifies himself as "a servant of Jesus Christ and a brother of James" — notably not claiming brotherhood with Jesus directly, though that relationship is implied (Mark 6:3; Matt 13:55 list both Jude and James among Jesus\'s brothers). The self-designation as <em>doulos</em> (servant) rather than "brother of the Lord" (Paul\'s term for James in Gal 1:19) reflects the same christological modesty seen in James 1:1. The letter\'s heavy use of 1 Enoch, the Assumption of Moses, and OT typology points to a Jewish-Christian audience, probably in Syria or Palestine. Dating is disputed: ca. 60-70 CE if by the historical Jude bar Joseph, or ca. 80-100 CE if pseudonymous under his authority.</p>',
    "2": '<p>"Mercy, peace and love be yours in abundance" — a triple blessing that expands the standard greeting. Jewish letters opened with "peace" (<em>shalom</em>); Paul christianized the greeting to "grace and peace"; Jude adds "mercy" and "love" to form a three-element formula. The abundance-language (<em>plēthyntheiē</em>, optative: may it be multiplied) echoes the LXX blessing-formulas and Daniel\'s opening (Dan 4:1 Theodotion: "may your peace be multiplied"). The triple formula anticipates the letter\'s closing triad (vv20-21): praying in the Spirit, keeping in God\'s love, waiting for Christ\'s mercy.</p>',
    "3": '<p>"Contend for the faith once for all delivered to the saints" — <em>epagonizesthai</em> is a compound of the athletic contest-word <em>agōn</em>, evoking the gymnasium culture of the Greco-Roman world where athletic contest was a fundamental social institution. Paul uses the same imagery extensively (1 Cor 9:24-27; Phil 3:14; 1 Tim 6:12). The faith as "once for all delivered" (<em>hapax paradotheisē</em>) positions the gospel deposit within the technical Jewish tradition of <em>masorah</em> (received tradition): the faith is not an evolving development but a fixed handing-over from the apostles — a closed tradition that must be guarded, not revised. The pivot from a planned letter "about the salvation we share" to an urgent defense implies a crisis precipitated by the infiltration of v4.</p>',
    "5": '<p>"The Lord at one time delivered his people out of Egypt, but later destroyed those who did not believe" — the wilderness generation as a negative type is standard in Second Temple Jewish exhortation and early Christianity (1 Cor 10:1-11; Heb 3:7-4:11). The Israelites delivered from Egypt but destroyed in the wilderness because of unbelief (Num 14:22-23, 28-35: none of those who saw the Exodus signs would enter the land except Caleb and Joshua) became the paradigmatic warning against presuming on election without fidelity. Jude reframes the wilderness apostasy as fundamentally a faith-failure (<em>tous mē pisteusantas</em>) — already anticipating the antinomians who presume on grace.</p>',
    "6": '<p>"Angels who did not keep their positions of authority but abandoned their proper dwelling" — this refers to the Watchers tradition of 1 Enoch 6-16, developed from Gen 6:1-4 ("sons of God saw the daughters of men"). In 1 Enoch, the Watchers are angelic beings who descend from heaven, take human wives, and corrupt humanity — for which they are bound in darkness awaiting final judgment (1 Enoch 10:4-6: "bind Azazel hand and foot and throw him into darkness"). The <em>archē</em> (position/station) they abandoned is their ordered place in the divine economy; the <em>oikētērion</em> (proper dwelling) is their heavenly station. Multiple copies of Aramaic Enoch fragments from Qumran confirm this tradition\'s wide currency in Second Temple Judaism. Jude presupposes his audience\'s familiarity with the Watchers story.</p>',
    "7": '<p>Sodom and Gomorrah gave themselves up to immorality and "went after different/strange flesh" (<em>sarkos heteras</em>) — the phrase is exegetically contested. In the Enochic tradition, the Watchers of Gen 6 sought human women (angels crossing to the human realm); the Sodomites of Gen 19 sought the angels. Placing this verse between the Watcher-episode (v6) and the dreamers (v8) suggests a deliberate parallel: both the angels and the Sodomites transgressed the heaven-earth boundary in opposite directions. Second Temple treatments of Sodom (T. Asher 7; 2 Enoch 10; Philo, Abr. 134-136) emphasize boundary-violation as the core sin. Sodom serves as an <em>hypodeigma</em> (example/type) of coming eternal fire judgment.</p>',
    "8": '<p>"On the strength of their dreams these ungodly people pollute their bodies, reject authority (<em>kyriotēta</em>), and heap abuse on celestial beings (<em>doxas blasphēmousin</em>)" — the triple accusation mirrors the three examples of vv5-7: body-pollution parallels Sodom\'s sexual transgression (v7); rejecting authority parallels the Watchers\' abandonment of their God-given station (v6); abusing celestial beings parallels Israel\'s rebellion against divine authority (v5). "On the strength of their dreams" (<em>enypniazoumenoi</em>) probably refers to visionary experiences the false teachers cited as authorization — the prophetic tradition\'s concern that false prophecy came through dreams (Jer 23:25-32; Deut 13:1-5) underlies this charge.</p>',
    "9": '<p>Jude here quotes or paraphrases the Assumption of Moses (also called the Testament of Moses), a Jewish apocalyptic text known from a 6th-century Latin manuscript fragment. The text described a dispute between Michael and Satan over Moses\'s burial (derived from Deut 34:5-6, where God buried Moses and "no one knows his burial place to this day"). Early Christian writers (Origen, Clement of Alexandria) cite this tradition; the mainstream patristic view became that Jude quotes a genuine tradition embedded in a non-canonical text, not that the whole text is Scripture. The theological point: if even the archangel Michael — superior to any created being — deferred to divine authority rather than pronouncing personal condemnation, how much more presumptuous are the false teachers who slander angelic powers. The "Lord rebuke you" formula echoes Zech 3:2.</p>',
    "10": '<p>"They slander whatever they do not understand, and the very things they do understand by instinct — as irrational animals — will destroy them" — the <em>alogos zōa</em> (unreasoning/speechless animals) are contrasted with the rational human capacity for understanding the divine. The Aristotelian tradition distinguished human beings (as <em>zōon logikon</em>, rational animals) from mere animals (governed by instinct alone); this distinction was widely current in Hellenistic philosophical discourse. The irony: the false teachers who boast of superior spiritual knowledge operate epistemically below the human level — their understanding extends only to what they share with animals (sexual appetite, material gain). The things they understand by instinct are precisely the things that will destroy them.</p>',
    "11": '<p>"Woe to them! They have taken the way of Cain; they have rushed for profit into Balaam\'s error; they have been destroyed in Korah\'s rebellion" — a triad of OT apostasy-archetypes standard in Jewish haggadic tradition as types of spiritual failure. Cain (Gen 4): in rabbinic tradition, the archetypal murderer and materialist (Philo, Sacr. 3: Cain represents self-love over love of God; Josephus Ant. 1.52-66 emphasizes his greed). Balaam (Num 22-24, 31): the prophet who sold his gift for wages (Num 22:7; 31:16: he counseled the Moabite women to seduce Israel) — the archetype of profit-motivated false prophecy. Korah (Num 16): who led a rebellion against Moses\'s God-given authority; 250 leaders perished when the earth swallowed them. The triple "woe" format invokes the prophetic tradition (Amos 5:18; Isa 5:8-25).</p>',
    "12": '<p>"These people are blemishes at your love feasts (<em>agapais</em>)" — the <em>agapē</em> meal was an early Christian communal meal closely associated with the Lord\'s Supper, at which the community ate together as an expression of covenant love (1 Cor 11:20-22 shows the Corinthian abuses of this meal). Jude\'s opponents corrupt the agape by eating "without the slightest qualm" (<em>aphobōs</em>, fearlessly/shamelessly). "Shepherds who feed only themselves" alludes to Ezek 34:2-4 (woe to the shepherds who feed themselves, not the flock) — a standard Second Temple image for corrupt leadership. The natural imagery — clouds without rain, uprooted autumn trees "twice dead" — is drawn from the Jewish wisdom tradition where waterless clouds and fruitless trees image moral vacuity (Wis 17:5; Sir 40:13).</p>',
    "13": '<p>"Wandering stars (<em>asteres planētai</em>), for whom blackest darkness has been reserved forever" — in 1 Enoch 18:14-16 and 21:1-6, stars that "transgressed the commandment of God before their time" are imprisoned in chaotic darkness, bound until the great day of judgment. Jude identifies the false teachers with these imprisoned stars: they wander from their proper course (like the Watchers who abandoned their proper station, v6), and the same eternal darkness reserved for the fallen stars awaits them. <em>Planētai</em> (wandering) in Greek astronomical usage referred to the five known planets whose paths differed from the fixed stars — they did not keep their courses. The metaphor fuses astronomical observation with the Enochic judgment-tradition.</p>',
    "14": '<p>"Enoch, the seventh from Adam, prophesied about them" — the identification of Enoch as "seventh from Adam" (matching the Gen 5 genealogy: Adam, Seth, Enosh, Kenan, Mahalalel, Jared, Enoch) aligns with 1 Enoch\'s own self-presentation. 1 Enoch was not part of the Hebrew canon but was treated as authoritative in many Second Temple communities — the Dead Sea Scrolls include multiple Aramaic Enoch fragments, indicating its wide use at Qumran. Jude\'s quotation of 1 Enoch 1:9 is the only direct NT quotation of a non-canonical Jewish text as prophetic. Early church debate over whether this constitutes canonical endorsement of 1 Enoch was extensive (Tertullian accepted it; Jerome and Augustine did not); the mainstream view became that Jude quotes a genuine tradition embedded in a non-canonical source, not that the whole Enoch corpus is Scripture.</p>',
    "15": '<p>The fourfold repetition of "ungodly" (<em>asebeis/asebeia/asebein/asebōs</em>) mirrors the rhetorical intensification of the 1 Enoch source text (1 Enoch 1:9: "to destroy all the ungodly, and to convict all flesh of all the works of ungodliness which they have ungodly worked"). This is the Semitic rhetorical device of anaphora combined with polyptoton — the same root word cycling through different grammatical forms to accumulate rhetorical force. "Defiant words" (<em>sklerōn hōn elalēsan</em>, harsh/hard things they have spoken) echoes Mal 3:13 LXX ("your words were harsh — <em>sklēra</em> — against me, says the Lord") — another prophetic warrant for the coming judgment on those who spoke against God.</p>',
    "16": '<p>"These people are grumblers (<em>gongystaí</em>) and faultfinders" — <em>gongystaí</em> is the LXX word for Israel\'s wilderness murmuring against God and Moses (Exod 16:7-9; Num 14:27: "how long will this wicked congregation grumble against me?"). By using this word Jude connects the false teachers back to the wilderness generation he invoked in v5: both are defined by the same fundamental attitude of discontent with divine provision and authority. "They boast about themselves and flatter others for their own advantage" — the boastfulness and flattery-for-profit describe the social behavior of Greco-Roman sophists who cultivated wealthy patrons through flattery and charged fees for teaching (Lucian satirizes this type mercilessly in his <em>Rhetorum Praeceptor</em>).</p>',
    "17": '<p>"Remember what the apostles of our Lord Jesus Christ foretold" — the appeal to apostolic prophecy about last-days false teachers is consistent across the Pauline and Petrine corpus: Acts 20:29-30 (Paul\'s Miletus speech: "savage wolves will come in among you"); 1 Tim 4:1-3 ("in later times some will depart from the faith"); 2 Tim 3:1-9; 2 Pet 3:1-4. Jude\'s "remember" (<em>mnēsthēte</em>) positions the community not as passive recipients of new information but as keepers of a prophetic tradition already delivered. The apostolic deposit (v3: "once for all delivered") included not only the gospel but the warning about the gospel\'s opponents. The appearance of the scoffers is itself confirmation that the apostles were right.</p>',
    "18": '<p>"In the last times there will be scoffers who will follow their own ungodly desires" — "the last times" (<em>ep\' eschatou [tou] chronou</em>) is the early Christian designation for the present period between resurrection and return, marked by intensifying apostasy. The same warning appears in 2 Pet 3:3 ("in the last days scoffers will come"), 1 Tim 4:1, and 2 Tim 3:1 ("in the last days there will come times of difficulty"). The consistency of this apostolic warning created a self-authenticating pattern: the appearance of scoffers fulfills the prophecy and thus confirms the authority that predicted them. The false teachers unwittingly prove the apostles\' reliability.</p>',
    "19": '<p>"These are the people who divide you, who follow mere natural instincts (<em>psychikoi</em>) and do not have the Spirit" — <em>psychikoi</em> is Paul\'s term for the "natural/soulish person" who cannot receive the things of the Spirit of God (1 Cor 2:14: <em>psychikos anthrōpos de ou dechetai ta tou pneumatos</em>). This vocabulary was a Pauline technical coinage that proto-Gnostic teachers seized and inverted — claiming that they were the <em>pneumatikoi</em> (spiritual ones) while ordinary believers were the <em>psychikoi</em>. Jude reverses the inversion: the false teachers who claim spiritual superiority are revealed as <em>psychikoi</em> — the very category they applied contemptuously to others. The "divisive" label (<em>apodiorizontes</em>, making separations) names the ecclesial effect of their spiritual elitism.</p>',
    "20": '<p>"Building yourselves up in your most holy faith and praying in the Holy Spirit" — the contrast with v19\'s "not having the Spirit" is deliberate: the true community does have the Spirit, and their Spirit-prompted prayer is the evidence. "Building up" (<em>epoikodountes</em>) is Paul\'s construction-metaphor for the church\'s corporate formation (1 Cor 3:10-15; Eph 2:20-22). "Most holy faith" (<em>tē hagiōtatē pistei</em>) is the superlative: the faith that the saints received (v3) is supremely holy because of its object. "Praying in the Holy Spirit" appears in Eph 6:18 as the mode of the community\'s sustained prayer-warfare — the Spirit-sustained intercession that sustains the community under pressure.</p>',
    "21": '<p>"Keep yourselves in God\'s love as you wait for the mercy of our Lord Jesus Christ to bring you to eternal life" — the imperative "keep yourselves" (<em>tērēsate heautous</em>) stands in productive tension with v24 (God who keeps — <em>phylaxai</em> — the community from stumbling). This is the consistent NT pattern of divine sovereignty and human responsibility held together without resolution: Phil 2:12-13 ("work out your salvation... for it is God who works in you"), and 1 Pet 1:5 ("who by God\'s power are being guarded through faith for a salvation"). The "mercy of our Lord Jesus Christ" that brings eternal life is the same mercy invoked in the greeting of v2 — Jude frames the letter with the mercy that begins and ends the Christian life.</p>',
    "22": '<p>"Be merciful to those who doubt" — the pastoral differentiation in vv22-23 reflects community triage: not all those influenced by false teaching are equally implicated. Those who "doubt" (<em>diakrinomenous</em>) are the wavering — the community is to show them mercy. Graduated pastoral responses to different grades of sin were developed in Second Temple Jewish communities: the Dead Sea Scrolls (1QS 5-6) distinguish levels of community discipline based on the severity of infraction. Paul similarly distinguishes the weak (Rom 14-15; 1 Cor 8-10), the fallen (Gal 6:1), and the willfully rebellious (1 Cor 5:1-5). Jude\'s tripartite distinction (doubters, those snatched from fire, those requiring cautious mercy) reflects the same pastoral sophistication.</p>',
    "23": '<p>"Snatching them from the fire" — alludes to Zech 3:2 ("Is not this a brand plucked from the fire?") — the same text Jude echoed in v9 (Michael\'s "the Lord rebuke you" formula from Zech 3:2). "Hating even the clothing (<em>chitōna</em>) stained by corrupted flesh" reflects Second Temple purity concerns: the tunic that touched a corpse-contaminated body could transmit impurity (Num 19:14-16; Lev 15:4-12). The pastoral approach to those deeply involved with false teaching requires a fearful caution — showing mercy while maintaining sharp distance from the practices that caused contamination. The same pastoral judgment appears in Paul\'s instructions about the sexually immoral in 1 Cor 5:5 (handing over to Satan for the destruction of the flesh) and the restoration of the fallen in Gal 6:1 (restore gently, watching yourself).</p>',
    "24": '<p>"To him who is able to keep you from stumbling (<em>aptaistous</em>) and to present you before his glorious presence without fault (<em>amōmous</em>) and with great joy" — the doxology\'s opening is a liturgical formula that likely circulated in early Christian worship. <em>Aptaistos</em> (without stumbling, sure-footed) is a rare word used in classical Greek for horses that do not slip; Philo uses it for the soul that does not stumble (Philo, Mig. 150). <em>Amōmos</em> (without blemish) is the sacrificial term — the technical word for an animal qualified for sacrifice (LXX Exod 29:1; Num 6:14). The eschatological presentation of believers before God is framed as a final cultic presentation: the community is offered to God as the ultimate unblemished sacrifice through Christ\'s own atonement.</p>',
    "25": '<p>"To the only God our Savior be glory, majesty, power and authority, through Jesus Christ our Lord, before all ages, now and forevermore! Amen" — the four attributes (glory, majesty, dominion, authority) mirror the heavenly throne-room liturgy of Revelation (Rev 4:11; 5:13) and the doxologies of Jewish synagogue prayer. "Before all ages" (<em>pro pantos tou aiōnos</em>) was a creedal formula resisting the Gnostic limitation of divine attributes to the present aeon — God\'s glory predates every created order. The "through Jesus Christ" mediation of a doxology to "the only God" reflects the pattern of early Christian liturgical prayer: Jewish-rooted doxology to the one God, channeled through the mediation of the risen Lord. Jude closes the NT\'s most apocalyptically charged letter with the scope of eternal divine sovereignty that dwarfs all the false teachers\' pretensions.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'jude')
    merge_comm(existing, CONTEXT)
    save_comm('mkt-context', 'jude', existing)

    il = json.loads((ROOT / 'data' / 'interlinear' / 'jude.json').read_text())
    il_vv = set(il.get('1', {}).keys())
    out_vv = set(existing.get('1', {}).keys())
    missing = sorted(il_vv - out_vv, key=int)
    if missing:
        print(f'  ch1: still missing {missing}')
    else:
        print(f'  ch1: complete ({len(out_vv)} verses) ✓')

if __name__ == '__main__':
    main()
